+impl FromValue for u8 {
+    fn from_value(value: &Value) -> Result<Self> {
+        let v = value.as_i64().ok_or_else(|| {
+            Error::Type(TypeError {
+                expected: "u8",
+                actual: value.type_name().to_string(),
+                column: None,
+                rust_type: None,
+            })
+        })?;
+        u8::try_from(v).map_err(|_| {
+            Error::Type(TypeError {
+                expected: "u8",
+                actual: format!("value {} out of range", v),
+                column: None,
+                rust_type: None,
+            })
+        })
+    }
+}
